        body: JSON.stringify({ success: true }),
      };

    case 'leaveRoom':
      console.log('User', userId, 'leaving room', roomId);
      return {
        statusCode: 200,
        body: JSON.stringify({ success: true }),
      };

    default:
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'Unknown action' }),
      };
  }
};

